def test_build_meeting_metadata_excludes_none():
    """Test that None values are excluded from artifact dicts."""
    event = CalendarEvent(
        event_id="evt1",
        calendar_id="cal1",
        summary="Test",
        start="2026-03-15T10:00:00Z",
        end="2026-03-15T11:00:00Z",
    )
    artifacts = [
        Artifact(
            type="transcript",
            title="Transcript",
            source_url="https://example.com/file",
            drive_file_id=None,  # Should be excluded
            local_file=None,  # Should be excluded
            mime_type="text/plain",
            source=None,  # Should be excluded
            note=None,  # Should be excluded
        )
    ]
    meeting = MeetingRecord(event=event, artifacts=artifacts)

    metadata = build_meeting_metadata(meeting)

    artifact = metadata["artifacts"][0]
    assert "type" in artifact
    assert "title" in artifact
    assert "source_url" in artifact
    assert "mime_type" in artifact
    assert "drive_file_id" not in artifact
    assert "local_file" not in artifact
    assert "source" not in artifact
    assert "note" not in artifact


