def test_build_and_write_index(tmp_path, sample_meeting):
    """Test building and writing the index from sidecar files."""
    # Write a few metadata files
    metadata1 = build_meeting_metadata(sample_meeting)
    filename1 = metadata_filename(sample_meeting)
    write_metadata(metadata1, tmp_path, filename1)

    # Create another meeting for different date
    event2 = CalendarEvent(
        event_id="evt456",
        calendar_id="cal456",
        summary="Another Meeting",
        start="2026-03-10T14:00:00Z",
        end="2026-03-10T15:00:00Z",
    )
    meeting2 = MeetingRecord(event=event2)
    metadata2 = build_meeting_metadata(meeting2)
    filename2 = metadata_filename(meeting2)
    write_metadata(metadata2, tmp_path, filename2)

    # Build index
    index_path = build_and_write_index(tmp_path)

    assert index_path == tmp_path / "index.json"
    assert index_path.exists()

    with open(index_path) as f:
        index = json.load(f)

    assert len(index) == 2
    # Should be sorted by date descending
    assert index[0]["date"] == "2026-03-15"
    assert index[1]["date"] == "2026-03-10"


