def test_refresh_all_metadata(tmp_path):
    """Test refreshing metadata from api_responses."""
    # Create initial metadata with outdated top-level fields
    initial_metadata = {
        "event_id": "evt123",
        "calendar_id": "cal456",
        "summary": "Old Title",
        "start": "2026-03-15T14:00:00Z",
        "end": "2026-03-15T15:00:00Z",
        "recurring_event_id": "rec789",
        "meet_code": "abc-defg-hij",
        "artifacts": [],
        "api_responses": {
            "calendar": {
                "id": "evt123",
                "summary": "Updated Title",
                "start": {"dateTime": "2026-03-15T14:30:00Z"},
                "end": {"dateTime": "2026-03-15T15:30:00Z"},
                "recurringEventId": "rec999",
            },
            "meet": {},
        },
    }
    write_metadata(initial_metadata, tmp_path, "test.meta.json")

    # Refresh
    count = refresh_all_metadata(tmp_path)

    assert count == 1

    # Verify updated metadata
    with open(tmp_path / "test.meta.json") as f:
        updated = json.load(f)

    assert updated["summary"] == "Updated Title"
    assert updated["start"] == "2026-03-15T14:30:00Z"
    assert updated["end"] == "2026-03-15T15:30:00Z"
    assert updated["recurring_event_id"] == "rec999"
    # event_id and calendar_id should not change
    assert updated["event_id"] == "evt123"
    assert updated["calendar_id"] == "cal456"


def test_refresh_all_metadata_multiple_files(tmp_path):
    """Test refreshing multiple metadata files."""
    for i in range(3):
        metadata = {
            "event_id": f"evt{i}",
            "calendar_id": "cal1",
            "summary": "Old",
            "start": "2026-03-15T10:00:00Z",
            "end": "2026-03-15T11:00:00Z",
            "recurring_event_id": None,
            "meet_code": None,
            "artifacts": [],
            "api_responses": {
                "calendar": {
                    "id": f"evt{i}",
                    "summary": f"Updated {i}",
                    "start": {"dateTime": "2026-03-15T10:00:00Z"},
                    "end": {"dateTime": "2026-03-15T11:00:00Z"},
                },
                "meet": {},
            },
        }
        write_metadata(metadata, tmp_path, f"test{i}.meta.json")

    count = refresh_all_metadata(tmp_path)

    assert count == 3

    for i in range(3):
        with open(tmp_path / f"test{i}.meta.json") as f:
            updated = json.load(f)
        assert updated["summary"] == f"Updated {i}"
